class DeepLinkHandler {
  static final DeepLinkHandler _instance = DeepLinkHandler._internal();
  factory DeepLinkHandler() => _instance;
  DeepLinkHandler._internal();

  static final GlobalKey<NavigatorState> navigatorKey = GlobalKey<NavigatorState>();

  Future<void> initDeepLinks() async {
    try {
      // Handle initial link
      Uri initialUri = await getInitialUri();
      if (initialUri != null) {
        _handleUri(initialUri);
      }

      // Listen for future links
      uriLinkStream.listen((Uri uri) {
        _handleUri(uri);
      }, onError: (err) {
        // Handle error
        print('Error handling deep link: $err');
      });
    } catch (e) {
      print('Error initializing deep links: $e');
    }
  }

  void _handleUri(Uri uri) {
    if (uri == null) return;

    final path = uri.path;
    final queryParameters = uri.queryParameters;

    switch (path) {
      case '/profile':
        final id = queryParameters['id'] ?? uri.pathSegments.last;
        _navigateToProfile(id);
        break;
      case '/payment':
        final action = uri.pathSegments.last;
        if (action == 'confirm') {
          _navigateToPaymentConfirmation(queryParameters);
        }
        break;
      default:
        // Handle default case or unknown paths
        _navigateToDefault();
    }
  }

  void _navigateToProfile(String id) {
    navigatorKey.currentState?.pushNamed('/profile', arguments: {'id': id});
  }

  void _navigateToPaymentConfirmation(Map<String, String> params) {
    navigatorKey.currentState?.pushNamed('/payment/confirm', arguments: params);
  }

  void _navigateToDefault() {
    navigatorKey.currentState?.pushNamed('/');
  }

  // Method to handle external URLs for fallback
  static Future<void> handleExternalUrl(String url) async {
    try {
      final uri = Uri.parse(url);
      if (uri.scheme == 'myapp') {
        _instance._handleUri(uri);
      } else {
        await launchUrl(uri);
      }
    } catch (e) {
      print('Error handling external URL: $e');
    }
  }
}

